@namespace Lumeo
@inject Services.IComponentInteropService Interop
@implements IAsyncDisposable

<div id="@_hostId"
     class="@CssClass"
     style="position: relative; overflow: hidden; --ripple-opacity: @Opacity.ToString("0.##", System.Globalization.CultureInfo.InvariantCulture); --ripple-duration: @(Math.Max(0, DurationMs))ms"
     @onpointerdown="OnPointerDown"
     @attributes="AdditionalAttributes">
    @ChildContent
    @foreach (var ripple in _ripples)
    {
        <span @key="@ripple.Id"
              class="lumeo-touch-ripple-span"
              style="left: @(ripple.X.ToString("0.##", System.Globalization.CultureInfo.InvariantCulture))px; top: @(ripple.Y.ToString("0.##", System.Globalization.CultureInfo.InvariantCulture))px; color: @Color;">
        </span>
    }
</div>

@code {
    /// <summary>The content the ripple overlays — the ripple host wraps this and spawns ripple spans on
    /// pointer-down over it.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Color of the ripple. Default: <c>currentColor</c>.</summary>
    [Parameter] public string Color { get; set; } = "currentColor";
    /// <summary>Peak opacity of the ripple as it expands. Default: 0.25.</summary>
    [Parameter] public double Opacity { get; set; } = 0.25;
    /// <summary>Duration of the ripple expand/fade animation in milliseconds, and how long its DOM node
    /// stays mounted before removal. Negative values are clamped to 0. Default: 500.</summary>
    [Parameter] public int DurationMs { get; set; } = 500;
    /// <summary>Additional CSS classes merged onto the ripple host <c>div</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Additional HTML attributes captured and forwarded to the ripple host <c>div</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _fallbackId = LumeoIds.New("touch-ripple");
    // A consumer-supplied id wins (it lands on the element after @attributes),
    // so the JS coordinate lookup must target the id actually in the DOM.
    private string _hostId => LumeoIds.Effective(AdditionalAttributes, _fallbackId);

    private string CssClass => Cx.Merge("lumeo-touch-ripple", Class);

    private record RippleEntry(Guid Id, double X, double Y);

    private readonly List<RippleEntry> _ripples = new();
    private readonly List<CancellationTokenSource> _pendingCts = new();

    private async Task OnPointerDown(PointerEventArgs e)
    {
        // prefers-reduced-motion: don't spawn a ripple at all. The CSS also
        // disables the span animation as defence-in-depth, but skipping here
        // avoids running a cleanup timer for an invisible element.
        if (await Interop.PrefersReducedMotion())
        {
            return;
        }

        // Resolve the click point relative to the ripple HOST element.
        // PointerEventArgs.OffsetX/OffsetY are relative to whatever child the
        // pointer actually landed on, so a ripple hosted around an icon/label
        // spawned off-centre. The JS helper subtracts the host's bounding rect
        // from the viewport clientX/clientY. Falls back to the raw offsets when
        // interop is unavailable (prerender / no JS) or returns the (0,0)
        // default for a click genuinely at the host origin.
        var point = await Interop.TouchRippleCoords(_hostId, e.ClientX, e.ClientY);
        var x = point.X;
        var y = point.Y;
        if (x == 0 && y == 0 && (e.OffsetX != 0 || e.OffsetY != 0))
        {
            x = e.OffsetX;
            y = e.OffsetY;
        }

        var ripple = new RippleEntry(Guid.NewGuid(), x, y);
        _ripples.Add(ripple);
        StateHasChanged();

        // Schedule removal AFTER the CSS animation without blocking the event
        // handler: the handler's returned Task must complete now so the ripple
        // is observable immediately (and a held pointer doesn't keep the
        // handler "running" for the whole duration). The detached continuation
        // marshals the state change back onto the renderer's sync context.
        var cts = new CancellationTokenSource();
        _pendingCts.Add(cts);
        _ = RemoveAfterDelayAsync(ripple, cts);
    }

    private async Task RemoveAfterDelayAsync(RippleEntry ripple, CancellationTokenSource cts)
    {
        try
        {
            // Clamp negatives: Task.Delay throws ArgumentOutOfRangeException for any
            // negative value other than -1, which would leak the ripple entry (the
            // fire-and-forget continuation never reaches the removal below).
            await Task.Delay(Math.Max(0, DurationMs), cts.Token);
        }
        catch (TaskCanceledException)
        {
            return;
        }
        finally
        {
            _pendingCts.Remove(cts);
            cts.Dispose();
        }

        _ripples.Remove(ripple);
        await InvokeAsync(StateHasChanged);
    }

    public async ValueTask DisposeAsync()
    {
        foreach (var cts in _pendingCts.ToList())
        {
            cts.Cancel();
            cts.Dispose();
        }
        _pendingCts.Clear();
        await ValueTask.CompletedTask;
    }
}
